module RefModule(
   input                clk,
   input                clr_n,
   input                en,
   input [31:0]         d,

   output reg [31:0]    q
);
  wire _tap_clk = clk & {1{1'b1}};

    always@(posedge clk or negedge clr_n)begin
        if(!clr_n) q <= 32'd0;
        else if(en) q <= d;
    end
endmodule
